package main

import (
	"fmt"
	"github.com/cilium/tetragon/api/v1/tetragon"
	"google.golang.org/protobuf/proto"
)

func main() {
	p1 := &tetragon.Pod{
		Namespace: "test",
		Name:      "test-pod",
		PodUid:    "test-uid-12345",
	}

	fmt.Println("PodUid via GetPodUid:", p1.GetPodUid())

	desc := p1.ProtoReflect().Descriptor()
	fmt.Printf("Fields in Pod:\n")
	for i := 0; i < desc.Fields().Len(); i++ {
		f := desc.Fields().Get(i)
		fmt.Printf("  %d: %s (num=%d, kind=%v)\n", i, f.Name(), f.Number(), f.Kind())
	}

	p2 := &tetragon.Pod{
		Namespace: "test",
		Name:      "test-pod",
		PodUid:    "test-uid-12345",
	}
	fmt.Printf("proto.Equal: %v (expected true)\n", proto.Equal(p1, p2))

	p3 := &tetragon.Pod{
		Namespace: "test",
		Name:      "test-pod",
		PodUid:    "different-uid",
	}
	fmt.Printf("proto.Equal with diff UID: %v (expected false)\n", proto.Equal(p1, p3))

	// Marshal and unmarshal to verify wire format
	data, err := proto.Marshal(p1)
	if err != nil {
		fmt.Println("Error marshaling:", err)
		return
	}
	fmt.Printf("Marshaled size: %d\n", len(data))

	var p4 tetragon.Pod
	if err := proto.Unmarshal(data, &p4); err != nil {
		fmt.Println("Error unmarshaling:", err)
		return
	}
	fmt.Printf("Unmarshaled PodUid: %q (expected: %q)\n", p4.PodUid, p1.PodUid)
	fmt.Println("Round-trip successful:", p4.PodUid == p1.PodUid)
}

